-- Fix residual Chinese text in the English/French recipe overlays.
-- Base recipe content remains DB-sourced; this only patches affected i18n rows.
with patch (recipe_id, lang, name, category, description, ingredients, steps, tags) as (values
  ('howtocook:aquatic/清蒸鲈鱼/清蒸鲈鱼', 'en', 'Steamed Sea Bass', 'Seafood', 'Steamed sea bass is a classic Cantonese steamed dish. The fish meat is tender and smooth, light and fresh, retaining the original flavor of the sea bass to the greatest extent. Sea bass is rich in high-quality protein and DHA, nutritious and easy to digest. This dish is simple to prepare and very beginner-friendly, taking about 30 minutes from prep to serving.', '[{"name":"Sea bass","unit":"whole"},{"name":"Scallions","unit":"stalk"},{"name":"Ginger","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Steamed fish soy sauce","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Slice the ginger into pieces and then into thin strips. Cut the white parts of the scallions into sections, and slice the green parts into thin strips. Soak the scallion strips in cold water and set aside.","After cleaning the sea bass, pat dry with paper towels. Make a few cuts on both sides. Rub the fish with salt to remove the slime, then rub 10g of salt all over the inside and outside of the fish. Marinate for at least 10 minutes.","Here''s a tip for cutting and plating the sea bass: after scoring, the fish can stand upright while steaming, ensuring even heating and making it easier to eat without flipping.","Score the fish","Steamed sea bass preview image 2","Stuff the fish belly with ginger and scallion whites, and also sprinkle some on top. Use half of the prepared amount. Place chopsticks under the fish in the steaming plate to lift it off the bottom.","Heat the water until it''s warm to the touch, then place the fish in the steamer.","Steam over high heat for 10 minutes.","Transfer the steamed fish to a clean plate and remove the ginger and scallions from the fish.","Drizzle 15ml of steamed fish soy sauce over the fish.","Sprinkle fresh ginger and scallion strips on the fish. Heat 10ml of cooking oil in a pan until hot, then pour the hot oil over the fish. Serve."]'::jsonb, '["Seafood","Steamed","Cantonese","Light","Tender","Home-style"]'::jsonb),
  ('howtocook:dessert/炸鲜奶/炸鲜奶', 'en', 'Fried Milk Custard', 'Desserts', 'Fried Milk Custard is a classic dessert with a crispy exterior and creamy interior, sweet and delicious. It''s a home-style snack. Rich in protein and calcium, with balanced nutrition. Medium difficulty, beginners can try. Preparation time about 20 minutes, but requires 1 hour refrigeration to set.', '[{"name":"Milk","unit":"g"},{"name":"Cornstarch","unit":"g"},{"name":"Breadcrumbs","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"White sugar","unit":"g"}]'::jsonb, '["Pour the milk into a bowl.","Add cornstarch and sugar, stir until well combined.","Brush the mold with cooking oil.","Pour the milk mixture into the pot, bring to a boil over medium heat.","After boiling, reduce to low heat, stirring constantly.","When the milk thickens, remove from heat and pour into the mold.","Place the mold in the refrigerator to cool for 1 hour.","Take it out, cut into evenly sized strips, then place in a bowl.","Pour half of the breadcrumbs into the bowl, coat the milk strips, then remove and set aside.","In a new bowl, beat the eggs and mix well, set aside.","Coat the milk strips with egg wash and the remaining breadcrumbs.","Pour enough oil into the pot to cover the strips, then fry them.","When the strips turn golden, turn off the heat and plate."]'::jsonb, '["Dessert","Sweet","Fried","Crispy outside and tender inside","Home-style dessert","Afternoon tea"]'::jsonb),
  ('howtocook:meat_dish/水煮肉片', 'en', 'Boiled Sliced Pork in Chili Sauce', 'Meat Dishes', 'Boiled sliced pork in chili sauce is a classic Sichuan dish with spicy and numbing flavor, tender sliced meat, and crunchy vegetables. It is excellent with rice. Pork tenderloin provides high-quality protein, combined with bean sprouts and other vegetables for balanced nutrition. The preparation process is a bit elaborate, especially the marination of the meat and making the knife-cut chilies. Beginners may need about 1 to 2 hours.', '[{"name":"Pork tenderloin","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Ground white pepper","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"Egg white","unit":"piece"},{"name":"Potato starch","unit":"g"},{"name":"Vegetable oil","unit":"g"},{"name":"Mung bean sprouts","unit":"g"},{"name":"Lettuce","unit":"piece"},{"name":"Celery","unit":"stalk"},{"name":"Garlic sprouts","unit":"stalk"},{"name":"Garlic","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Pickled red chilies","unit":"g"},{"name":"Green Sichuan peppercorns","unit":"g"},{"name":"Dried chilies","unit":"g"},{"name":"Red oil doubanjiang","unit":"ml"},{"name":"Chicken powder","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Rapeseed oil","unit":"g"}]'::jsonb, '["Cut the tenderloin into small pieces, then slice into 2mm thin slices (adjust thickness to preference). Place in a bowl, wash with water twice to remove blood and impurities, drain and squeeze dry.","Add 1.5g salt, 1g white pepper, 5g light soy sauce, 3g cooking wine to the bowl. Stir in one direction for 2 minutes to season.","In another bowl, mix one egg white with 7g potato starch, stir evenly in one direction, then pour into the meat.","Stir again in one direction until the meat surface forms a smooth coating, making the meat more tender.","Finally, add 30g vegetable oil and gently mix (to prevent the slices from sticking).","100g mung bean sprouts, 1 lettuce (cut into strips), 3 celery stalks cut into segments, 2 garlic sprouts crushed and cut into segments.","20g garlic minced, small piece of ginger minced, 20g pickled red chilies minced.","15g dried small chili peppers, 3g green Sichuan peppercorns. Heat oil in a wok, swirl to coat, pour out excess leaving 50g oil. Add dried chilies and peppercorns, stir-fry on low heat until fragrant and the color turns dark (be careful not to burn). Transfer to a cutting board and chop finely.","Heat the wok, add 100g vegetable oil to 60% heat. Add 2g green Sichuan peppercorns and dried chilies for aroma. Add the vegetables, 1g salt, stir-fry until just cooked. Transfer to a bowl as a base.","Clean the wok, add 150g vegetable oil to 60% heat. Add the prepared ginger, garlic, and pickled chilies, stir until fragrant. Add 10g doubanjiang (red oil chili bean paste), stir-fry on low heat until the oil turns red.","Add 800ml water (adjust as needed). Bring to a boil over high heat, then reduce to low heat. Season with 2.5g salt, 1.5g chicken powder, 1g sugar for freshness, 1g white pepper, 5g water starch slurry (adjust as needed) to thicken the soup slightly.","When the soup is boiling, turn to low heat and slide the marinated meat slices one by one into the soup. Then turn to medium heat to cook the meat slices. Gently push with a spatula to prevent sticking. When the soup boils again and the meat is cooked, remove the meat and place on top of the vegetables in the bowl. Pour the soup over (not exceeding the ingredients).","Evenly sprinkle the chopped dried chili mixture, minced garlic, and chopped scallions on top.","Clean the wok, add 200g rapeseed oil, heat to 70% heat (smoking). Then pour the hot oil evenly over the meat in the bowl (be careful of safety). Ready to serve."]'::jsonb, '["Meat Dish","Spicy and Numbing","Sichuan","Rice Dish","Boiled","Banquet"]'::jsonb),
  ('howtocook:meat_dish/猪肉烩酸菜', 'en', 'Pork Braised with Sauerkraut', 'Meat Dishes', 'Pork braised with sauerkraut is a Northern Chinese home-style stew, with rich sour aroma, tender pork belly, and flavorful ribs. It mainly provides protein, and the sauerkraut also brings beneficial components like lactic acid bacteria. The steps are clear and easy for beginners to follow, but requires patient slow cooking, taking about 3 hours from start to finish.', '[{"name":"Pork belly or pork ribs","unit":"g"},{"name":"Northeastern sauerkraut","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"clove"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Five-spice powder","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"Star anise","unit":"piece"}]'::jsonb, '["Cut the scallions into sections; cut 50g of ginger into sections and 50g into minced ginger; mince the garlic; set aside.","Shred all the sauerkraut, rinse with water 2 to 3 times, and set aside.","Put the ribs and pork belly into a pot, pour in cold water to submerge. Add all the scallion sections, 50g ginger sections, and 20ml cooking wine. Bring to a boil over high heat, then wait 5 minutes. Turn off the heat, remove the ribs and pork belly, rinse with cold water to remove scum, and set aside.","Slice or chunk the cooked pork belly, and set aside.","Wash the previous pot clean and dry it (otherwise the oil will splatter when added).","Add oil to the pot over medium heat, sauté the minced ginger and garlic until fragrant, then add the pork belly and ribs. Fry until golden, then add 10g five-spice powder and 15g light soy sauce, stirring with a spatula for 1-2 minutes.","Add the rinsed sauerkraut shreds to the pot and stir-fry for 3 minutes.","Pour in purified water until the ingredients are just submerged, add 2 star anise, turn to high heat until the water boils. Then reduce to medium heat, cover, and simmer.","Wait 1.5 to 2 hours until the pork belly is tender (can be easily pierced with chopsticks).","Remove the lid, turn to high heat to reduce the sauce, stirring the ingredients until only a thin layer of liquid covers the bottom, then turn to low heat, ready to season.","Seasoning: add 10g of salt, stir well.","Turn off the heat and serve."]'::jsonb, '["Meat Dish","Sour and Aromatic","Stew","Northern","Home-style","Appetizing with Rice"]'::jsonb),
  ('howtocook:meat_dish/辣椒炒肉', 'en', 'Stir-fried Pork with Green Peppers', 'Meat Dishes', 'Stir-fried pork with green peppers is a home-style dish with rich Hunan flavor. The peppers are dry-fried until slightly charred, and the pork slices are tender and flavorful. It''s salty, savory, and mildly spicy, making it a great accompaniment to rice. Pork is rich in high-quality protein and B vitamins, while green peppers provide abundant vitamin C. This dish requires mastery of dry-frying and quick-stirring techniques, suitable for those with some cooking experience. From preparation to serving, it takes about 30 minutes.', '[{"name":"Green peppers","unit":"piece"},{"name":"Lean pork","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Garlic","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Fermented black beans","unit":"g"}]'::jsonb, '["Wash the green peppers, remove the stems and seeds, then cut into bite-sized pieces using a rolling cut (cut on the bias, turning the pepper as you go).","Smash the garlic cloves with the side of a knife, then slice crosswise into pieces. Finely chop the ginger into mince.","Slice the pork along the grain, keeping the knife parallel to the meat fibers so the finished slices show clear parallel streaks.","Rinse the sliced pork, place in a bowl, then add the measured light soy sauce, oyster sauce, and salt. Mix well and marinate for 10 minutes.","Heat the wok without oil, add the cut green peppers. Dry-fry over high heat until they develop a ''tiger skin'' appearance (blistered and slightly charred). Then add 2g salt and stir-fry for another minute. Remove and set aside.","Without cleaning the wok, heat it over high heat, add 8ml oil. After 30 seconds, add the garlic and ginger, stir-fry for 15 seconds.","Add the marinated pork to the wok, stir-fry for 2 minutes, then add the dry-fried green peppers and stir-fry for another minute.","Add fermented black beans (douchi) to taste, then add dark soy sauce. Continue stir-frying for 30 seconds.","Remove from heat and plate."]'::jsonb, '["Meat Dish","Hunan Cuisine","Salty, Savory, Mildly Spicy","Dry-fried","Quick Stir-fry","Goes well with rice","Home-style"]'::jsonb),
  ('howtocook:vegetable_dish/家常日本豆腐', 'en', 'Homestyle Japanese Tofu', 'Vegetarian', 'Homestyle Japanese Tofu is a quick and easy home-cooked dish with a crispy outside and tender inside. Golden crust wraps silky egg tofu, paired with green pepper, carrot, and other vegetables. It can be seasoned with savory or sweet and sour flavors, crispy and tender. Japanese tofu is mainly made from eggs, rich in high-quality protein, plus wood ear mushrooms and vegetables for balanced nutrition. It requires a bit of pan-frying skill, moderate difficulty, but beginners can try. It takes about 30 minutes to serve.', '[{"name":"Japanese tofu","unit":"g"},{"name":"Green pepper","unit":"g"},{"name":"Carrot","unit":"g"},{"name":"Ham sausage","unit":"g"},{"name":"Black wood ear mushrooms","unit":"g"},{"name":"Cornstarch","unit":"g"},{"name":"Onion","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"Ketchup","unit":"ml"}]'::jsonb, '["Slice the carrot, cut the green pepper into thin pieces, mince the green onion and garlic.","Open the packaged Japanese tofu, cut into cylinders about 1 cm thick.","Put cornstarch in a flat plate, ready to coat the tofu.","Gently place the tofu on the cornstarch, coat both sides and edges, being careful not to coat too thickly.","Add 150 ml oil to a flat pan, enough to submerge most of the tofu. When the edges turn golden, flip and fry the other side.","When both sides are fried, remove and set aside on a clean plate.","Pour 10-15 ml oil into a wok, add green onion and garlic, stir-fry until fragrant, then add green pepper, carrot, ham sausage, and black wood ear mushrooms.","Add oyster sauce, light soy sauce, salt, chicken bouillon, white sugar, and ketchup.","Gently stir-fry until the colors are evenly distributed."]'::jsonb, '["Vegetarian","Pan-fried","Savory","Sweet and Sour","Quick","Rice-friendly"]'::jsonb),
  ('howtocook:aquatic/清蒸鲈鱼/清蒸鲈鱼', 'fr', 'Bar vapeur', 'Fruits de mer', 'Le bar vapeur est un plat de vapeur classique cantonais. La chair du poisson est tendre et lisse, la saveur est légère et délicieuse, maximisant la saveur naturelle du bar. Le bar est riche en protéines de haute qualité et en DHA, nutritif et facile à digérer. Ce plat est simple à réaliser, très accessible aux débutants, et prend environ trente minutes de la préparation à la cuisson.', '[{"name":"Bar","unit":"pièce"},{"name":"Oignons verts","unit":"tige"},{"name":"Gingembre","unit":"morceau"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja pour poisson vapeur","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Couper le gingembre en tranches puis en filaments, couper le blanc des oignons verts en tronçons et le vert en filaments. Tremper les filaments dans de l''eau froide et réserver.","Nettoyer le bar, l''essuyer avec du papier absorbant. Faire quelques entailles sur chaque face. Frotter le poisson avec du sel pour enlever le mucus, puis saler l''intérieur et l''extérieur avec 10 g de sel. Laisser mariner au moins 10 minutes.","Ajout d''une méthode de découpe et de présentation : après la découpe, le bar peut être cuit à la vapeur debout pour une cuisson uniforme et plus facile à manger sans avoir à le retourner.","Découpe","Image de prévisualisation du bar vapeur 2","Farcir l''intérieur du poisson avec du gingembre et du blanc d''oignon vert, et en parsemer également sur le corps. Utiliser la moitié de la quantité réservée. Placer des baguettes dans le plat de cuisson pour surélever le poisson et le cuire à la vapeur.","Porter l''eau à ébullition, puis ajouter le poisson.","Cuire à la vapeur à feu vif pendant 10 minutes.","Retirer le poisson cuit, le mettre dans un plat propre et enlever le gingembre et l''oignon vert.","Verser 15 ml de sauce soja pour poisson vapeur sur le poisson.","Parsemer de nouveau de filaments de gingembre et d''oignon vert. Chauffer 10 ml d''huile de cuisson dans une casserole, puis verser l''huile chaude sur le poisson. Servir."]'::jsonb, '["Poisson","Vapeur","Cantonnais","Léger","Tendre","Maison"]'::jsonb),
  ('howtocook:dessert/奥利奥冰淇淋/奥利奥冰淇淋', 'fr', 'Glace à l''Oréo', 'Desserts', 'La glace à l''Oréo est onctueuse, avec un mélange de saveur lactée et du croquant sucré des Oréo. La crème entière animale la rend légère et non grasse. Elle apporte principalement de l''énergie, des lipides et des glucides, parfaite comme petite douceur rafraîchissante. La préparation est simple : il suffit de retirer le fourrage des biscuits et de fouetter la crème. Un débutant patient peut y arriver. Comptez environ 30 minutes de préparation, puis 4 heures de congélation minimum.', '[{"name":"Crème liquide entière (marque recommandée : Anchor)","unit":"ml"},{"name":"Oréo original","unit":"pièces"},{"name":"Sucre blanc","unit":"g"}]'::jsonb, '["Ouvrir les Oréo, retirer la crème et réserver.","Écraser les biscuits Oréo avec une baguette. La moitié doit devenir une poudre, l''autre moitié doit rester en morceaux de moins de 0,5 cm. Réserver. (Sur Taobao, cherchez des miettes d''Oréo pour gagner du temps ^-^)","Verser toute la crème dans un grand bol et ajouter le sucre préparé.","Fouetter à vitesse élevée avec un batteur électrique jusqu''à ce que la crème forme des pics mous (0,5 cm à 1 cm) lorsqu''on soulève le batteur, et qu''elle ne coule plus comme un liquide (un peu de coulure est normal).","Une fois fouettée, incorporer les miettes d''Oréo et mélanger uniformément jusqu''à ce que le fond en contienne.","Optionnel : verser le mélange dans des moules à glace.","Placer au congélateur (à -18 °C) pendant au moins 4 heures avant de servir."]'::jsonb, '["Dessert","Lacté","Sucré","Surgelé","Rapide","Goûter"]'::jsonb),
  ('howtocook:drink/Mojito莫吉托', 'fr', 'Mojito', 'Boissons', 'Ce cocktail a un goût rafraîchissant, aigre-doux, avec la fraîcheur de la menthe et la légère ivresse du rhum. C''est une boisson estivale classique. Peu alcoolisé, il est accompagné de citron vert riche en vitamine C, ce qui stimule la salivation, désaltère et rafraîchit l''esprit. La préparation est très simple, adaptée aux débutants, et ne prend qu''environ dix minutes de la mise en place à la finition.', '[{"name":"Citron vert","unit":"morceau"},{"name":"Feuilles de menthe","unit":"branche"},{"name":"Sirop","unit":"ml"},{"name":"Rhum ambré","unit":"ml"},{"name":"Vodka naturelle Blue Sky","unit":"ml"},{"name":"Glaçon pilé","note":"quantité suffisante"},{"name":"Eau de Seltz glacée","note":"quantité suffisante"}]'::jsonb, '["Couper un des demi-citrons verts en petits morceaux, les mettre dans un verre highball, puis les écraser avec un pilon pour en extraire le jus ;","Frotter le bord du verre avec 3-4 branches de menthe, puis les mettre dans le verre ;","Ajouter 20 ml de sirop ;","Ajouter 45 ml de rhum ambré ;","Presser le jus de l''autre demi-citron vert et le verser dans le verre ;","Remuer doucement pour que le sucre/le sirop soit à moitié dissous ;","Mettre de la glace pilée dans le verre jusqu''à remplir les 3/4 ;","Ajouter de l''eau de Seltz glacée jusqu''à juste recouvrir la glace pilée ;","Tourner et remuer pendant une demi-minute ;","Remplir le verre highball avec de la glace pilée ;","Frapper la dernière branche de menthe pour réveiller son arôme, l''insérer dans la glace pilée pour décorer."]'::jsonb, '["Boisson","Aigre-doux","Rafraîchissant","Cocktail","Rapide","Été"]'::jsonb),
  ('howtocook:meat_dish/红烧鸡翅', 'fr', 'Ailes de poulet braisées à la sauce soja', 'Plats de viande', 'Les ailes de poulet braisées sont un plat familial qui accompagne bien le riz. Elles sont salées et légèrement sucrées, d''une couleur rouge brillante, avec une viande tendre qui se détache facilement des os. Les ailes de poulet sont riches en protéines de haute qualité et en collagène, faciles à absorber. La difficulté est modérée ; les débutants peuvent suivre les étapes facilement. Du début à la fin, il faut environ 40 minutes.', '[{"name":"ailes de poulet fraîches","unit":"grammes"},{"name":"tranches de gingembre","unit":"grammes"},{"name":"morceaux de ciboule","unit":"grammes"},{"name":"ail","unit":"grammes"},{"name":"feuille de laurier","unit":"feuille"},{"name":"anis étoilé","unit":"pièce"},{"name":"piments séchés","unit":"pièce"},{"name":"sucre candi (glace)","unit":"grammes"},{"name":"vin de riz jaune ou vin de cuisine","unit":"ml"},{"name":"sauce soja légère","unit":"ml"},{"name":"sauce soja foncée","unit":"ml"},{"name":"sel","unit":"grammes"},{"name":"sucre blanc","unit":"grammes"},{"name":"poivre blanc moulu","unit":"grammes"},{"name":"graines de sésame blanc","unit":"grammes"},{"name":"ciboule ciselée","unit":"grammes"},{"name":"huile de cuisson","unit":"ml"}]'::jsonb, '["Lavez les ailes de poulet. À l''aide d''un couteau, faites trois entailles sur la partie épaisse et une entaille sur le dos pour mieux imprégner les saveurs.","Si les ailes ne sont pas fraîches, après les avoir entaillées, faites-les tremper dans de l''eau gingembre pendant 10 à 20 minutes.","Préparez 10 grammes de tranches de gingembre (3-4 tranches), 15 grammes de morceaux de ciboule (2-3 morceaux) ; 3-4 gousses d''ail (environ 15 grammes) écrasées avec un couteau (sans les hacher) ; 1 feuille de laurier, 1 anis étoilé, 2 piments séchés (optionnel), réservez.","Mettez une casserole sur le feu, ajoutez assez d''eau froide pour couvrir toutes les ailes, puis ajoutez les ailes préparées, 20 ml de vin de riz jaune ou de vin de cuisine, 2 tranches de gingembre (environ 5 grammes). Portez à ébullition à feu vif, puis maintenez l''ébullition 2-3 minutes en écumant les impuretés.","Égouttez les ailes, rincez-les 2 fois à l''eau tiède pour éliminer complètement les impuretés, puis égouttez-les bien et réservez.","Dans une autre casserole, chauffez à feu vif puis ajoutez 10-15 ml d''huile de cuisson.","Lorsque l''huile est à 50% de chaleur, ajoutez 15 grammes de sucre candi (glace). Faites chauffer à feu vif jusqu''à ce que le sucre soit complètement fondu. Lorsqu''il change de couleur, passez à feu doux et continuez à remuer jusqu''à ce que le sucre prenne une couleur rouge foncé (couleur de jujube). Ajoutez immédiatement les ailes égouttées et faites-les sauter rapidement 1-2 minutes pour que chaque aile soit uniformément enrobée de caramel.","Ajoutez la feuille de laurier, l''anis étoilé, les 2 piments séchés (optionnel), les 2 tranches de gingembre restantes (environ 5 grammes), les 15 grammes de morceaux de ciboule et l''ail écrasé. Faites sauter encore 30 secondes jusqu''à ce que les arômes des épices se libèrent.","Versez 15 ml de vin de cuisine ou de vin de riz jaune le long du bord de la casserole, puis 15 ml de sauce soja légère. Faites sauter rapidement 10 secondes.","Ajoutez de l''eau tiède (environ 50-60°C) jusqu''à ce que les ailes soient juste couvertes.","Ajoutez 5 ml de sauce soja foncée, 3 grammes de sel, 2 grammes de sucre blanc, 1 gramme de poivre blanc moulu. Mélangez doucement avec une spatule.","Couvrez et laissez cuire à feu moyen pendant 7-8 minutes.","Retirez le couvercle, utilisez des baguettes pour retirer la feuille de laurier, l''anis étoilé, les tranches de gingembre, les morceaux de ciboule et l''ail, puis jetez-les.","Passez à feu vif et remuez continuellement jusqu''à ce que la sauce épaississe (environ 1-2 minutes).","Éteignez le feu, déposez les ailes dans une assiette et nappez-les de la sauce épaisse restante.","Saupoudrez de 3 grammes de graines de sésame blanc et 5 grammes de ciboule ciselée. C''est prêt !"]'::jsonb, '["Viande","Familial","Accompagnement du riz","Salé et umami","Braisé","Pour invités"]'::jsonb)
)
insert into public.recipe_i18n (recipe_id, lang, name, category, description, ingredients, steps, tags)
select recipe_id, lang, name, category, description, ingredients, steps, tags from patch
on conflict (recipe_id, lang) do update set
  name = excluded.name,
  category = excluded.category,
  description = excluded.description,
  ingredients = excluded.ingredients,
  steps = excluded.steps,
  tags = excluded.tags,
  updated_at = now();
